import{_ as l,p as i,q as e,a1 as n}from"./framework-5866ffd3.js";const u={},a=n('<h1 id="定义" tabindex="-1"><a class="header-anchor" href="#定义" aria-hidden="true">#</a> 定义</h1><p>用来表示人、事物、地点以及抽象事物的名称</p><p>人： John, sister, father</p><p>事物： water, air, sun, computer</p><p>地点: London, theater</p><p>抽象事物: love, happiness, imagination, hope</p><h1 id="分类" tabindex="-1"><a class="header-anchor" href="#分类" aria-hidden="true">#</a> 分类</h1><ul><li><p>专有名词 proper noun</p><ul><li>表示特定的人、物、机构或场所等的名词（首字母通常大写）</li></ul></li><li><p>普通名词 common noun</p><ul><li>可数名词 countable noun <ul><li>个体名词 <ul><li>表示同类的人或物中的个体</li></ul></li><li>集体名词 <ul><li>表示若干人或物的总称</li></ul></li></ul></li><li>不可数名词 uncountable noun <ul><li>物质名词 <ul><li>表示物质和材料的总称</li></ul></li><li>抽象名词 <ul><li>表示动作、性质、状态或情感等抽象概念的名词</li></ul></li></ul></li></ul></li><li><p>根据构成</p><ul><li>简单名词</li><li>复合名词 <ul><li>若干单词组合而成</li><li>girlfriend, roommate,mother-in-law</li></ul></li></ul></li></ul>',8),o=[a];function t(r,p){return i(),e("div",null,o)}const h=l(u,[["render",t],["__file","noun.html.vue"]]);export{h as default};
